-- Semester results (computed from grades; F -> BLOCKED, I -> BLOCKED)

INSERT INTO public.semester_results (student_user_id, semester_id, sgpa, status, blocked_reason)
SELECT
  s.user_id,
  co.semester_id,
  CASE
    WHEN bool_or(g.is_fail) OR bool_or(g.is_incomplete) THEN NULL
    ELSE ROUND( SUM(c.credits * gs.grade_point) / NULLIF(SUM(c.credits), 0), 2 )
  END AS sgpa,
  CASE
    WHEN bool_or(g.is_fail) OR bool_or(g.is_incomplete) THEN 'BLOCKED'::semester_result_status
    ELSE 'GENERATED'::semester_result_status
  END AS status,
  CASE
    WHEN bool_or(g.is_fail) THEN
      'Failing grade (F) in course ' || string_agg(c.code || ' ' || c.title, ', ') FILTER (WHERE g.is_fail)
      || ' — SGPA withheld until retake.'
    WHEN bool_or(g.is_incomplete) THEN
      'Incomplete grade (I) in course ' || string_agg(c.code || ' ' || c.title, ', ') FILTER (WHERE g.is_incomplete)
      || ' — SGPA withheld until completion.'
    ELSE NULL
  END AS blocked_reason
FROM public.students s
JOIN public.enrollments e     ON e.student_user_id = s.user_id AND e.status <> 'RETAKE'
JOIN public.course_offerings co ON co.id = e.course_offering_id
JOIN public.courses c         ON c.id = co.course_id
JOIN public.grades g          ON g.enrollment_id = e.id
LEFT JOIN public.grade_scale gs ON gs.letter = g.letter_grade
GROUP BY s.user_id, co.semester_id
ON CONFLICT (student_user_id, semester_id) DO UPDATE
  SET sgpa = EXCLUDED.sgpa,
      status = EXCLUDED.status,
      blocked_reason = EXCLUDED.blocked_reason;

