-- Payments (one PAID, one OVERDUE, one PARTIAL, plus normal rows)

DO $$
DECLARE r record; BEGIN
  FOR r IN SELECT user_id, current_semester_id FROM public.students WHERE current_semester_id IS NOT NULL LOOP
    INSERT INTO public.payments (student_user_id, semester_id, amount_due, amount_paid, due_date, status)
    VALUES (r.user_id, r.current_semester_id, 45000.00, 45000.00, CURRENT_DATE + INTERVAL '30 days', 'PAID')
    ON CONFLICT (student_user_id, semester_id) DO NOTHING;
  END LOOP;
END $$;

